# 对撞指针：两数之和（有序数组）
def two_sum(numbers, target):
    left, right = 0, len(numbers) - 1
    while left < right:
        current = numbers[left] + numbers[right]
        if current == target:
            return [left + 1, right + 1]  # 返回1-based索引
        elif current < target:
            left += 1  # 和太小，左指针右移增大数值
        else:
            right -= 1  # 和太大，右指针左移减小数值
    return [-1, -1]

# 快慢指针：检测链表是否有环
class ListNode:
    def __init__(self, val=0):
        self.val = val
        self.next = None

def has_cycle(head):
    if not head or not head.next:
        return False
    slow = head  # 慢指针，每次走一步
    fast = head.next  # 快指针，每次走两步
    while slow != fast:
        if not fast or not fast.next:
            return False  # 快指针到达末尾，无环
        slow = slow.next
        fast = fast.next.next
    return True  # 相遇则存在环
